import{_ as a,o,c as d,a2 as e}from"./chunks/framework.DS_HIvHc.js";const b=JSON.parse('{"title":"접근성 & 다양한 사용자 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"guide/accessibility.md","filePath":"guide/accessibility.md","lastUpdated":1773902344000}'),r={name:"guide/accessibility.md"};function l(i,t,s,n,c,h){return o(),d("div",null,[...t[0]||(t[0]=[e(`<h1 id="접근성-다양한-사용자-가이드" tabindex="-1">접근성 &amp; 다양한 사용자 가이드 <a class="header-anchor" href="#접근성-다양한-사용자-가이드" aria-label="Permalink to &quot;접근성 &amp; 다양한 사용자 가이드&quot;">​</a></h1><blockquote><p>모든 팀원이 편하게 쓸 수 있도록. 다양한 상황의 사용자를 위한 활용 팁입니다.</p></blockquote><h2 id="시니어-직원을-위한-가이드" tabindex="-1">시니어 직원을 위한 가이드 <a class="header-anchor" href="#시니어-직원을-위한-가이드" aria-label="Permalink to &quot;시니어 직원을 위한 가이드&quot;">​</a></h2><p>AI 도구가 처음이신 분들도 걱정하지 마세요. 복잡한 기술 지식 없이도 바로 시작할 수 있습니다.</p><h3 id="초간단-시작법" tabindex="-1">초간단 시작법 <a class="header-anchor" href="#초간단-시작법" aria-label="Permalink to &quot;초간단 시작법&quot;">​</a></h3><ol><li><strong>Claude Desktop을 엽니다</strong> — 프로그램 아이콘을 더블클릭하세요</li><li><strong>궁금한 것을 그냥 물어봅니다</strong> — 말하듯이 입력하면 됩니다</li><li><strong>답변을 확인하고 활용합니다</strong> — 복사해서 필요한 곳에 붙여넣기</li></ol><div class="info custom-block"><p class="custom-block-title">핵심 3가지만 기억하세요</p><ul><li><strong>질문하기</strong>: 대화창에 궁금한 것을 입력하고 Enter</li><li><strong>수정 요청</strong>: &quot;좀 더 짧게 해줘&quot;, &quot;존댓말로 바꿔줘&quot;처럼 추가 요청</li><li><strong>복사하기</strong>: 답변 옆의 복사 버튼(📋)을 눌러서 원하는 곳에 붙여넣기</li></ul></div><h3 id="큰-글씨-설정-방법" tabindex="-1">큰 글씨 설정 방법 <a class="header-anchor" href="#큰-글씨-설정-방법" aria-label="Permalink to &quot;큰 글씨 설정 방법&quot;">​</a></h3><table tabindex="0"><thead><tr><th>방법</th><th>설정 경로</th></tr></thead><tbody><tr><td><strong>브라우저 확대</strong></td><td><code>Ctrl</code> + <code>+</code> (확대) / <code>Ctrl</code> + <code>-</code> (축소) / <code>Ctrl</code> + <code>0</code> (원래 크기)</td></tr><tr><td><strong>Windows 디스플레이</strong></td><td>설정 → 디스플레이 → 배율 및 레이아웃 → 125% 또는 150%</td></tr><tr><td><strong>Mac 디스플레이</strong></td><td>시스템 설정 → 디스플레이 → 텍스트 크기 조절</td></tr></tbody></table><h3 id="자주-쓰는-프롬프트-즐겨찾기-활용" tabindex="-1">자주 쓰는 프롬프트 즐겨찾기 활용 <a class="header-anchor" href="#자주-쓰는-프롬프트-즐겨찾기-활용" aria-label="Permalink to &quot;자주 쓰는 프롬프트 즐겨찾기 활용&quot;">​</a></h3><p>매번 같은 질문을 다시 타이핑할 필요 없습니다. 자주 쓰는 프롬프트를 저장해두세요.</p><ul><li>메모장이나 스티커 메모에 자주 쓰는 문장을 저장</li><li>필요할 때 복사해서 붙여넣기</li><li>예시: &quot;이 이메일을 정중하게 다듬어줘&quot;, &quot;아래 내용을 표로 정리해줘&quot;</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>처음에는 간단한 질문부터 시작하세요. &quot;오늘 날씨 어때?&quot; 같은 가벼운 대화도 괜찮습니다. 점점 익숙해지면 업무에 활용해보세요.</p></div><h2 id="비개발-직군을-위한-가이드" tabindex="-1">비개발 직군을 위한 가이드 <a class="header-anchor" href="#비개발-직군을-위한-가이드" aria-label="Permalink to &quot;비개발 직군을 위한 가이드&quot;">​</a></h2><h3 id="코딩-이라는-단어가-나오면-당황하지-마세요" tabindex="-1">&quot;코딩&quot;이라는 단어가 나오면 당황하지 마세요 <a class="header-anchor" href="#코딩-이라는-단어가-나오면-당황하지-마세요" aria-label="Permalink to &quot;&quot;코딩&quot;이라는 단어가 나오면 당황하지 마세요&quot;">​</a></h3><p>Cowork는 코딩 도구가 아닙니다. <strong>대화형 업무 도우미</strong>입니다. 기획, 마케팅, 인사, 총무, 영업 등 어떤 직군이든 업무에 바로 활용할 수 있습니다.</p><h3 id="기술-용어-없이-설명하는-핵심-기능-5가지" tabindex="-1">기술 용어 없이 설명하는 핵심 기능 5가지 <a class="header-anchor" href="#기술-용어-없이-설명하는-핵심-기능-5가지" aria-label="Permalink to &quot;기술 용어 없이 설명하는 핵심 기능 5가지&quot;">​</a></h3><table tabindex="0"><thead><tr><th>기능</th><th>쉽게 말하면</th><th>활용 예시</th></tr></thead><tbody><tr><td><strong>문서 작성</strong></td><td>초안을 대신 써줌</td><td>&quot;거래처에 보낼 감사 이메일 써줘&quot;</td></tr><tr><td><strong>문서 요약</strong></td><td>긴 글을 짧게 정리</td><td>&quot;이 보고서 핵심만 3줄로 요약해줘&quot;</td></tr><tr><td><strong>표 정리</strong></td><td>데이터를 깔끔한 표로</td><td>&quot;이 숫자들 표로 만들어줘&quot;</td></tr><tr><td><strong>번역</strong></td><td>외국어를 한국어로, 한국어를 외국어로</td><td>&quot;이 영어 이메일 한국어로 번역해줘&quot;</td></tr><tr><td><strong>아이디어 브레인스토밍</strong></td><td>함께 아이디어를 내줌</td><td>&quot;신제품 마케팅 아이디어 5개 제안해줘&quot;</td></tr></tbody></table><h3 id="그냥-동료에게-부탁하듯이-말하면-됩니다" tabindex="-1">&quot;그냥 동료에게 부탁하듯이&quot; 말하면 됩니다 <a class="header-anchor" href="#그냥-동료에게-부탁하듯이-말하면-됩니다" aria-label="Permalink to &quot;&quot;그냥 동료에게 부탁하듯이&quot; 말하면 됩니다&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">이렇게 말해보세요</p><ul><li><p>❌ 어렵게: &quot;JSON 형식으로 구조화된 데이터를 파싱하여...&quot;</p></li><li><p>✅ 쉽게: &quot;이 데이터 보기 좋게 정리해줘&quot;</p></li><li><p>❌ 어렵게: &quot;마크다운 문법을 활용한 문서 포맷팅...&quot;</p></li><li><p>✅ 쉽게: &quot;이거 제목 넣고 번호 매겨서 깔끔하게 해줘&quot;</p></li></ul></div><h2 id="외국어-화자를-위한-가이드" tabindex="-1">외국어 화자를 위한 가이드 <a class="header-anchor" href="#외국어-화자를-위한-가이드" aria-label="Permalink to &quot;외국어 화자를 위한 가이드&quot;">​</a></h2><h3 id="한국어가-모국어가-아닌-팀원을-위한-팁" tabindex="-1">한국어가 모국어가 아닌 팀원을 위한 팁 <a class="header-anchor" href="#한국어가-모국어가-아닌-팀원을-위한-팁" aria-label="Permalink to &quot;한국어가 모국어가 아닌 팀원을 위한 팁&quot;">​</a></h3><p>Claude는 다국어를 지원합니다. 한국어가 어려우면 편한 언어로 시작해도 됩니다.</p><h3 id="영어로-질문해도-ok" tabindex="-1">영어로 질문해도 OK <a class="header-anchor" href="#영어로-질문해도-ok" aria-label="Permalink to &quot;영어로 질문해도 OK&quot;">​</a></h3><p>영어(또는 다른 언어)로 질문하면서 한국어 답변을 받을 수 있습니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Please summarize this document in Korean.</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Translate the following into Korean formal style:</span></span>
<span class="line"><span>&quot;We would like to schedule a meeting next week.&quot;</span></span></code></pre></div><h3 id="다국어-혼합-프롬프트-예시" tabindex="-1">다국어 혼합 프롬프트 예시 <a class="header-anchor" href="#다국어-혼합-프롬프트-예시" aria-label="Permalink to &quot;다국어 혼합 프롬프트 예시&quot;">​</a></h3><table tabindex="0"><thead><tr><th>상황</th><th>프롬프트 예시</th></tr></thead><tbody><tr><td>영어→한국어 보고서</td><td>&quot;Write a summary of this report in Korean (존댓말)&quot;</td></tr><tr><td>일본어 이메일 번역</td><td>&quot;この メールを韓国語に翻訳してください&quot;</td></tr><tr><td>중국어 자료 요약</td><td>&quot;把这份文件用韩语总结一下&quot;</td></tr><tr><td>혼합 질문</td><td>&quot;이 English document를 요약해줘&quot;</td></tr></tbody></table><h3 id="번역-기능-적극-활용" tabindex="-1">번역 기능 적극 활용 <a class="header-anchor" href="#번역-기능-적극-활용" aria-label="Permalink to &quot;번역 기능 적극 활용&quot;">​</a></h3><ul><li>회의록을 다국어로 동시 번역</li><li>해외 거래처 이메일을 자연스러운 한국어로</li><li>한국어 보고서를 영어로 변환하여 본사 공유</li><li>전문 용어가 포함된 기술 문서 번역</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Claude에게 &quot;쉬운 한국어로 설명해줘&quot; 또는 &quot;Please explain in simple Korean&quot;이라고 요청하면 외국어 화자도 이해하기 쉬운 답변을 받을 수 있습니다.</p></div><h2 id="시각적-도움이-필요한-분" tabindex="-1">시각적 도움이 필요한 분 <a class="header-anchor" href="#시각적-도움이-필요한-분" aria-label="Permalink to &quot;시각적 도움이 필요한 분&quot;">​</a></h2><h3 id="스크린-리더와-함께-사용하기" tabindex="-1">스크린 리더와 함께 사용하기 <a class="header-anchor" href="#스크린-리더와-함께-사용하기" aria-label="Permalink to &quot;스크린 리더와 함께 사용하기&quot;">​</a></h3><p>Claude Desktop은 텍스트 기반 인터페이스이므로 스크린 리더와 호환됩니다.</p><ul><li><strong>Windows</strong>: NVDA, JAWS 등의 스크린 리더를 켠 상태로 사용 가능</li><li><strong>Mac</strong>: VoiceOver(<code>Cmd</code> + <code>F5</code>)를 활성화하여 사용</li></ul><h3 id="키보드만으로-cowork-사용하기" tabindex="-1">키보드만으로 Cowork 사용하기 <a class="header-anchor" href="#키보드만으로-cowork-사용하기" aria-label="Permalink to &quot;키보드만으로 Cowork 사용하기&quot;">​</a></h3><table tabindex="0"><thead><tr><th>단축키</th><th>기능</th></tr></thead><tbody><tr><td><code>Tab</code></td><td>다음 요소로 이동</td></tr><tr><td><code>Shift</code> + <code>Tab</code></td><td>이전 요소로 이동</td></tr><tr><td><code>Enter</code></td><td>메시지 전송 / 버튼 실행</td></tr><tr><td><code>Ctrl</code> + <code>C</code></td><td>선택 영역 복사</td></tr><tr><td><code>Ctrl</code> + <code>V</code></td><td>붙여넣기</td></tr><tr><td><code>Ctrl</code> + <code>A</code></td><td>전체 선택</td></tr><tr><td><code>Ctrl</code> + <code>+</code> / <code>-</code></td><td>화면 확대 / 축소</td></tr></tbody></table><h3 id="고대비-모드-설정" tabindex="-1">고대비 모드 설정 <a class="header-anchor" href="#고대비-모드-설정" aria-label="Permalink to &quot;고대비 모드 설정&quot;">​</a></h3><table tabindex="0"><thead><tr><th>운영체제</th><th>설정 방법</th></tr></thead><tbody><tr><td><strong>Windows</strong></td><td>설정 → 접근성 → 대비 테마 → 높은 대비 선택</td></tr><tr><td><strong>Mac</strong></td><td>시스템 설정 → 손쉬운 사용 → 디스플레이 → 대비 증가</td></tr></tbody></table><h3 id="음성-입력-활용" tabindex="-1">음성 입력 활용 <a class="header-anchor" href="#음성-입력-활용" aria-label="Permalink to &quot;음성 입력 활용&quot;">​</a></h3><p>타이핑이 불편하다면 음성 입력을 사용해보세요.</p><ul><li><strong>Windows</strong>: <code>Win</code> + <code>H</code>로 음성 입력 활성화</li><li><strong>Mac</strong>: <code>Fn</code> + <code>Fn</code> (두 번 누르기)으로 받아쓰기 시작</li><li>말로 질문하고, Claude의 답변은 스크린 리더로 듣기</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>음성 입력과 스크린 리더를 조합하면 키보드나 마우스 없이도 Claude를 활용할 수 있습니다.</p></div><h2 id="재택-원격-근무자" tabindex="-1">재택/원격 근무자 <a class="header-anchor" href="#재택-원격-근무자" aria-label="Permalink to &quot;재택/원격 근무자&quot;">​</a></h2><h3 id="혼자-일할-때-claude를-동료처럼-활용" tabindex="-1">혼자 일할 때 Claude를 동료처럼 활용 <a class="header-anchor" href="#혼자-일할-때-claude를-동료처럼-활용" aria-label="Permalink to &quot;혼자 일할 때 Claude를 동료처럼 활용&quot;">​</a></h3><p>사무실에 동료가 없을 때, Claude가 대신할 수 있는 역할:</p><ul><li><strong>검토자</strong>: &quot;이 보고서 어색한 부분 있어?&quot; — 제출 전 검토</li><li><strong>브레인스토밍 파트너</strong>: &quot;이 주제로 아이디어 좀 내줘&quot; — 혼자 고민하지 않기</li><li><strong>편집자</strong>: &quot;이 문장 더 자연스럽게 다듬어줘&quot; — 문서 퇴고</li><li><strong>정보 정리</strong>: &quot;이 회의 내용 정리해줘&quot; — 회의록 작성</li></ul><h3 id="시간대가-다른-팀원과-비동기-협업" tabindex="-1">시간대가 다른 팀원과 비동기 협업 <a class="header-anchor" href="#시간대가-다른-팀원과-비동기-협업" aria-label="Permalink to &quot;시간대가 다른 팀원과 비동기 협업&quot;">​</a></h3><table tabindex="0"><thead><tr><th>상황</th><th>Claude 활용법</th></tr></thead><tbody><tr><td>해외 팀과 협업</td><td>영어 이메일 초안 작성 후 검토 요청</td></tr><tr><td>야간 긴급 요청</td><td>Claude에게 먼저 초안을 받아 다음 날 팀원에게 전달</td></tr><tr><td>다른 시간대 회의 준비</td><td>회의 안건과 요약본을 미리 작성</td></tr><tr><td>인수인계 문서</td><td>현재 진행 상황을 정리하여 다음 담당자에게 공유</td></tr></tbody></table><h3 id="재택에서-특히-유용한-기능-5가지" tabindex="-1">재택에서 특히 유용한 기능 5가지 <a class="header-anchor" href="#재택에서-특히-유용한-기능-5가지" aria-label="Permalink to &quot;재택에서 특히 유용한 기능 5가지&quot;">​</a></h3><ol><li><strong>회의록 정리</strong> — 화상 회의 내용을 붙여넣으면 깔끔하게 정리</li><li><strong>이메일 톤 조절</strong> — 상황에 맞는 적절한 톤으로 이메일 작성</li><li><strong>일일 업무 보고</strong> — 오늘 한 일을 나열하면 보고서 형식으로 변환</li><li><strong>자료 조사 요약</strong> — 긴 자료를 핵심만 추려서 정리</li><li><strong>일정 정리</strong> — 이번 주 할 일을 우선순위별로 정리</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>재택 근무 시작할 때 &quot;오늘 할 일 목록 정리해줘&quot;로 하루를 시작하고, 마무리할 때 &quot;오늘 한 일 요약해줘&quot;로 마감하면 업무 관리가 훨씬 수월합니다.</p></div><h2 id="관리자-팀-접근성-체크리스트" tabindex="-1">관리자: 팀 접근성 체크리스트 <a class="header-anchor" href="#관리자-팀-접근성-체크리스트" aria-label="Permalink to &quot;관리자: 팀 접근성 체크리스트&quot;">​</a></h2><p>팀 전체가 Cowork를 원활하게 사용할 수 있도록, 아래 항목을 정기적으로 점검하세요.</p><table tabindex="0"><thead><tr><th>항목</th><th>확인</th></tr></thead><tbody><tr><td>모든 팀원이 계정을 가지고 있는가?</td><td>☐</td></tr><tr><td>교육이 다양한 수준에 맞춰 제공되는가?</td><td>☐</td></tr><tr><td>도움을 요청할 채널(슬랙, 팀즈 등)이 있는가?</td><td>☐</td></tr><tr><td>다양한 기기(Mac/Windows)에서 테스트했는가?</td><td>☐</td></tr><tr><td>피드백 수집 채널이 있는가?</td><td>☐</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">관리자 팁</p><p>체크리스트를 분기마다 한 번씩 점검하세요. 신규 입사자가 있을 때는 반드시 온보딩 과정에 Cowork 교육을 포함하세요.</p></div><h2 id="자주-듣는-걱정과-답변" tabindex="-1">자주 듣는 걱정과 답변 <a class="header-anchor" href="#자주-듣는-걱정과-답변" aria-label="Permalink to &quot;자주 듣는 걱정과 답변&quot;">​</a></h2><table tabindex="0"><thead><tr><th>걱정</th><th>답변</th></tr></thead><tbody><tr><td>&quot;나는 디지털에 약해서...&quot;</td><td>스마트폰으로 메시지 보낼 수 있다면 Claude도 쓸 수 있습니다. 대화하듯 글을 입력하면 됩니다.</td></tr><tr><td>&quot;실수하면 어떡하죠?&quot;</td><td>실수해도 전혀 문제없습니다. Claude는 기계라서 기분 나빠하지 않고, 언제든 다시 질문할 수 있습니다. 회사 시스템에 영향을 주는 작업은 항상 확인 과정을 거칩니다.</td></tr><tr><td>&quot;내 일을 빼앗기는 건 아닌가요?&quot;</td><td>Claude는 도구입니다. 계산기가 회계사를 대체하지 않듯이, Claude는 반복적인 작업을 도와서 더 중요한 일에 집중할 시간을 만들어줍니다.</td></tr><tr><td>&quot;보안이 걱정돼요&quot;</td><td>회사에서 승인한 환경에서 사용하며, 민감한 정보(개인정보, 비밀번호 등)는 입력하지 않으면 됩니다. 보안 가이드라인을 따르면 안전합니다.</td></tr><tr><td>&quot;나이가 많아서 못 배울까봐...&quot;</td><td>나이는 전혀 상관없습니다. Claude는 어떤 속도로 질문해도 인내심 있게 답변합니다. 오히려 풍부한 업무 경험이 더 좋은 질문을 만듭니다.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>모든 사람이 AI의 혜택을 누릴 자격이 있습니다. 속도나 수준에 관계없이, 자신에게 맞는 방식으로 천천히 시작하세요. 어려울 때는 언제든 동료나 관리자에게 도움을 요청하세요.</p></div>`,60)])])}const q=a(r,[["render",l]]);export{b as __pageData,q as default};
